    approvalDecisionProduced: false,
    approvalDecisionPersisted: false,
    approvalDecisionId: null,
    approvalGrantProduced: false,
    approvalGrantPersisted: false,
    approvalGrantId: null,
    runtimePermissionGranted: false,
